const body = $input.first().json.body || {};
const now = new Date();
const missing = [];
if (!body.logid) missing.push('logid');
if (!body.logcontent) missing.push('logcontent');
const sessionId = body.sessionid || `sess-${body.logid || Date.now()}`;
const fileId = body.fileid || `file-${body.logid || Date.now()}`;
return [{
  json: {
    requestid: body.requestid || `reqingest-${Date.now()}`,
    sessionid: sessionId,
    fileid: fileId,
    mode: 'ingest',
    stage: 'logingestion',
    timestamp: now.toISOString(),
    ingestversion: 'phase2v1',
    source_type: 'eda_log',
    file_type: '.log',
    logid: body.logid || null,
    toolname: body.toolname || 'OpenROAD',
    verilogfiles: Array.isArray(body.verilogfiles) ? body.verilogfiles : [],
    logcontent: body.logcontent || null,
    rtlcontent: body.rtlcontent || null,
    context: body.context || null,
    topk: parseInt(body.topk, 10) || 5,
    startms: Date.now(),
    inputvalid: missing.length === 0,
    validationerrorcode: missing.length ? 'INVALIDINPUT' : null,
    validationerrormessage: missing.length ? `Missing required ${missing.join(', ')}` : null
  }
}];

const { logid, toolname, logcontent } = $input.first().json;
const patterns = {
  ERROR: /(ERROR|FATAL|CRITICAL)/i,
  WARNING: /(WARNING|CAUTION)/i,
  WNS: /WNS\s*(-?\d+\.?\d*)/i,
  TNS: /TNS\s*(-?\d+\.?\d*)/i,
  MULTIDRIVEN: /multi-?driven\s+net\s+([A-Za-z0-9_]+)/i,
  LATCH: /(latch\s+inferred|unexpected\s+latch)/i,
  VIOLATION: /(violation|setup\s+violation|hold\s+violation|fail)/i,
  FILELINE: /file\s+([A-Za-z0-9_\.\/\-]+)\s+(\d+)/i,
  NET: /net\s+([A-Za-z0-9_]+)/i,
  MODULE: /module\s+([A-Za-z0-9_]+)/i
};
const preprocessed = String(logcontent || '').replace(/\r/g, '').trim();
const lines = preprocessed.split('\n').map(l => l.trim()).filter(l => l.length > 0);
function getPriorityScore(meta) {
  let score = 0;
  if (meta.severity === 'ERROR') score += 1.0;
  else if (meta.severity === 'WARNING') score += 0.7;
  if (meta.hastimingviolation) score += 0.8;
  if ((meta.timingtns ?? 0) < 0) score += 0.3;
  if (meta.issuetype === 'MULTIDRIVEN') score += 0.6;
  if (meta.issuetype === 'LATCHINFERRED') score += 0.5;
  if (meta.file) score += 0.2;
  if (meta.net) score += 0.1;
  return Math.min(score, 2.0);
}
const chunks = [];
for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  if (!line || line.length < 3) continue;
  const metadata = {
    logid,
    tool: toolname,
    linenum: i + 1,
    severity: 'INFO'
  };
  if (patterns.ERROR.test(line)) metadata.severity = 'ERROR';
  else if (patterns.WARNING.test(line)) metadata.severity = 'WARNING';
  const wnsM = line.match(patterns.WNS);
  if (wnsM) {
    metadata.timingwns = parseFloat(wnsM[1]);
    metadata.hastimingviolation = metadata.timingwns < 0;
  }
  const tnsM = line.match(patterns.TNS);
  if (tnsM) metadata.timingtns = parseFloat(tnsM[1]);
  if (patterns.MULTIDRIVEN.test(line)) {
    const m = line.match(patterns.MULTIDRIVEN);
    metadata.issuetype = 'MULTIDRIVEN';
    metadata.net = m?.[1] || null;
  } else if (patterns.LATCH.test(line)) {
    metadata.issuetype = 'LATCHINFERRED';
  } else if (patterns.VIOLATION.test(line)) {
    metadata.issuetype = 'VIOLATION';
  }
  const flM = line.match(patterns.FILELINE);
  if (flM) {
    metadata.file = flM[1];
    metadata.fileline = parseInt(flM[2], 10);
  }
  const netM = line.match(patterns.NET);
  if (netM && !metadata.net) metadata.net = netM[1];
  const modM = line.match(patterns.MODULE);
  if (modM) metadata.module = modM[1];
  const priority = getPriorityScore(metadata);
  chunks.push({ text: line, metadata, priority });
}
const highPriority = chunks.filter(c => c.priority >= 0.3).sort((a, b) => b.priority - a.priority);
const keepCount = Math.max(1, Math.floor(chunks.length * 0.8));
const finalChunks = highPriority.length > 0 ? highPriority.slice(0, keepCount) : chunks.filter(c => c.metadata.severity !== 'INFO');
return [{
  json: {
    logid,
    toolname,
    totallines: lines.length,
    errorcount: chunks.filter(c => c.metadata.severity === 'ERROR').length,
    warningcount: chunks.filter(c => c.metadata.severity === 'WARNING').length,
    timingviolations: chunks.filter(c => c.metadata.hastimingviolation).length,
    chunks: finalChunks
  }
}];

const uploadItems = $input.all();
const firstMeta = $('Process - Split Chunks').first().json;
let successCount = 0;
let duplicateCount = 0;
let failedCount = 0;
const uploads = uploadItems.map((item, index) => {
  const j = item.json || {};
  const rawStatus = j.status || j.data?.status || j.result?.status || 'unknown';
  const status = String(rawStatus).toLowerCase();
  const ok = status === 'success' || status === 'duplicated' || status === 'duplicate' || status === 'already_exists';
  if (status === 'success') successCount++;
  else if (status === 'duplicated' || status === 'duplicate' || status === 'already_exists') duplicateCount++;
  else failedCount++;
  return {
    index: index + 1,
    filepath: firstMeta.filepath,
    status: rawStatus,
    message: j.message || j.error || j.detail || null,
    trackid: j.trackid || j.data?.trackid || null,
    ok,
    raw: j
  };
});
return [{
  json: {
    requestid: firstMeta.requestid,
    sessionid: firstMeta.sessionid,
    fileid: firstMeta.fileid,
    mode: firstMeta.mode,
    stage: firstMeta.stage,
    timestamp: firstMeta.timestamp,
    ingestversion: firstMeta.ingestversion,
    startms: firstMeta.startms,
    logid: firstMeta.logid,
    toolname: firstMeta.toolname,
    verilogfiles: firstMeta.verilogfiles,
    parsertotallines: firstMeta.parsertotallines,
    parsererrorcount: firstMeta.parsererrorcount,
    parserwarningcount: firstMeta.parserwarningcount,
    parsertimingviolations: firstMeta.parsertimingviolations,
    parserchunkcount: firstMeta.parserchunkcount,
    uploadok: failedCount === 0 && uploads.length > 0,
    uploadtotal: uploads.length,
    uploadsuccesscount: successCount,
    uploadduplicatecount: duplicateCount,
    uploadfailedcount: failedCount,
    uploads
  }
}];

const meta = $('Process - Extract Metadata').first().json;
const parser = $('Process - EDA Log Parser').first().json;
const upload = $('Process - Normalize Upload Result').first().json;
const chunks = parser.chunks || [];
const issueTypeLabel = {
  VIOLATION: 'Timing Violation',
  MULTIDRIVEN: 'Multi-Driven Net',
  LATCHINFERRED: 'Latch Inferred'
};
function findChunk(predicate) {
  return chunks.find(predicate);
}
const topChunk = chunks[0] || null;
const wnsChunk = findChunk(c => c.metadata?.timingwns !== undefined);
const tnsChunk = findChunk(c => c.metadata?.timingtns !== undefined);
const locationChunk = findChunk(c => c.metadata?.file && c.metadata?.fileline);
const issueChunk = findChunk(c => c.metadata?.issuetype === 'VIOLATION') || findChunk(c => c.metadata?.issuetype === 'MULTIDRIVEN') || findChunk(c => c.metadata?.issuetype === 'LATCHINFERRED');
const primaryIssueType = issueTypeLabel[issueChunk?.metadata?.issuetype] || 'General';
const primaryLocation = locationChunk ? `${locationChunk.metadata.file}:${locationChunk.metadata.fileline}` : (topChunk?.metadata?.net || 'NA');
const topSeverity = topChunk?.metadata?.severity || 'INFO';
const evidence = chunks.slice(0, 10).map((c, index) => ({
  evidenceid: `ingestev-${index + 1}`,
  sourcetype: 'parsedlogline',
  label: issueTypeLabel[c.metadata?.issuetype] || `${c.metadata?.severity} Log Evidence`,
  severity: c.metadata?.severity || 'INFO',
  location: c.metadata?.file ? `${c.metadata.file}:${c.metadata.fileline}` : (c.metadata?.net || 'NA'),
  message: c.text,
  score: c.priority || 0,
  metadata: {
    issuetype: c.metadata?.issuetype || null,
    module: c.metadata?.module || null,
    net: c.metadata?.net || null,
    timingwns: c.metadata?.timingwns ?? null,
    timingtns: c.metadata?.timingtns ?? null,
    linenum: c.metadata?.linenum ?? null
  }
}));
return [{
  json: {
    requestid: meta.requestid,
    sessionid: meta.sessionid,
    fileid: meta.fileid,
    mode: meta.mode,
    stage: meta.stage,
    timestamp: meta.timestamp,
    subjectid: meta.logid,
    summary: {
      title: 'Log ingested and indexed',
      rootcause: `Primary parsed issue is ${primaryIssueType}.`,
      primarylocation: primaryLocation,
      recommendedfix: 'Use debug workflow for root-cause analysis and fix guidance based on indexed evidence.',
      severity: topSeverity
    },
    details: {
      logid: meta.logid,
      toolname: meta.toolname,
      verilogfiles: meta.verilogfiles,
      ingestversion: meta.ingestversion,
      source_type: meta.source_type,
      file_type: meta.file_type,
      parsersummary: {
        primaryissuetype: primaryIssueType,
        wns: wnsChunk?.metadata?.timingwns ?? null,
        tns: tnsChunk?.metadata?.timingtns ?? null
      },
      uploadsummary: {
        uploadtotal: upload.uploadtotal,
        uploadsuccesscount: upload.uploadsuccesscount,
        uploadduplicatecount: upload.uploadduplicatecount,
        uploadfailedcount: upload.uploadfailedcount
      }
    },
    evidence,
    risk: {
      level: parser.errorcount > 0 ? 'medium' : 'low'
    },
    guardrail: {
      passed: true,
      warnings: [],
      blocks: [],
      recommendedchecks: [
        'Run cloud debug for diagnosis',
        'Review top parsed violations',
        'Confirm timing impact if WNS/TNS is negative'
      ]
    },
    metrics: {
      latencyms: Date.now() - meta.startms,
      totallines: parser.totallines,
      errorcount: parser.errorcount,
      warningcount: parser.warningcount,
      timingviolations: parser.timingviolations,
      chunkcount: chunks.length,
      uploadtotal: upload.uploadtotal,
      uploadsuccesscount: upload.uploadsuccesscount,
      uploadduplicatecount: upload.uploadduplicatecount,
      uploadfailedcount: upload.uploadfailedcount
    },
    raw: {
      parseroutput: parser,
      uploadoutput: upload
    }
  }
}];

const meta = $('Process - Extract Metadata').first().json;
const parser = $('Process - EDA Log Parser').first().json;
const chunks = parser.chunks || [];
return [{
  json: {
    requestid: meta.requestid,
    sessionid: meta.sessionid,
    fileid: meta.fileid,
    logid: meta.logid,
    chunkcount: chunks.length,
    chunksql: chunks.map((c, index) => {
      const chunkId = `${meta.logid}-chunk-${index + 1}`;
      const pointId = `${meta.logid}-p-${index + 1}`;
      const severity = c.metadata?.severity || 'INFO';
      const issuetype = c.metadata?.issuetype || '';
      const priority = Number(c.priority || 0);
      const metadata = JSON.stringify(c.metadata || {}).replace(/'/g, "''");
      return `INSERT INTO eda_chunks (chunk_id, session_id, logid, file_id, source_type, file_type, qdrant_collection, qdrant_point_id, severity, issuetype, priority, metadata) VALUES ('${chunkId}','${meta.sessionid}','${meta.logid}','${meta.fileid}','eda_log','.log','eda_log_chunks','${pointId}','${severity}','${issuetype}',${priority},'${metadata}'::jsonb) ON CONFLICT (chunk_id) DO UPDATE SET session_id=EXCLUDED.session_id, logid=EXCLUDED.logid, file_id=EXCLUDED.file_id, source_type=EXCLUDED.source_type, file_type=EXCLUDED.file_type, qdrant_collection=EXCLUDED.qdrant_collection, qdrant_point_id=EXCLUDED.qdrant_point_id, severity=EXCLUDED.severity, issuetype=EXCLUDED.issuetype, priority=EXCLUDED.priority, metadata=EXCLUDED.metadata;`;
    }).join('\n')
  }
}];

const data = $('Process - Build Phase 1 Ingest Response').first().json;
return [{
  json: {
    success: true,
    requestid: data.requestid,
    mode: data.mode,
    stage: data.stage,
    subjectid: data.subjectid,
    sessionid: data.sessionid,
    fileid: data.fileid,
    timestamp: data.timestamp,
    summary: data.summary,
    details: {
      ...data.details,
      databasewrite: {
        session: true,
        file_registry: true,
        chunk_registry: true,
        audit_log: true
      }
    },
    evidence: data.evidence,
    risk: data.risk,
    guardrail: data.guardrail,
    metrics: data.metrics,
    raw: data.raw
  }
}];

const inputCtx = $('Process - Validate Input').first().json;
const current = $input.first().json || {};
let error = { code: 'INGESTFAILED', message: 'Ingest pipeline failed before indexing completed.', stage: 'logingestion', retryable: true, httpstatus: 500 };
if (!inputCtx.inputvalid) {
  error = {
    code: inputCtx.validationerrorcode || 'INVALIDINPUT',
    message: inputCtx.validationerrormessage || 'Invalid input.',
    stage: 'inputvalidation',
    retryable: false,
    httpstatus: 400
  };
} else if (current.uploadok === false) {
  error = {
    code: 'LIGHTRAGUPLOADFAILED',
    message: `LightRAG upload failed for ${current.uploadfailedcount || 0} chunks.`,
    stage: 'lightragupload',
    retryable: true,
    httpstatus: 503
  };
}
return [{
  json: {
    success: false,
    requestid: inputCtx.requestid,
    mode: inputCtx.mode,
    stage: inputCtx.stage,
    subjectid: inputCtx.logid,
    sessionid: inputCtx.sessionid,
    fileid: inputCtx.fileid,
    timestamp: inputCtx.timestamp,
    error,
    summary: null,
    details: {
      logid: inputCtx.logid,
      toolname: inputCtx.toolname,
      ingestversion: inputCtx.ingestversion
    },
    evidence: [],
    risk: { level: 'low' },
    guardrail: {
      passed: true,
      warnings: [],
      blocks: [],
      recommendedchecks: [
        'Verify input payload',
        'Check LightRAG service health',
        'Retry ingest after dependency recovery'
      ]
    },
    metrics: {
      latencyms: Date.now() - inputCtx.startms
    },
    raw: current
  }
}];

